prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?nodeType ?nodeName 
       (COUNT(DISTINCT ?outgoing) AS ?outgoingCount)
       (COUNT(DISTINCT ?reachableEnd) AS ?endsReached)
WHERE {
  VALUES ?choreo { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> }
  VALUES ?start { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-A013B90C-3DC6-4212-8569-1E2B58402B21> }
  VALUES ?end { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-E23D1D47-0985-461A-A5F1-774792B4BDCB> }

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?node .
  ?node tai:belongsTo ?choreo .
  ?node a ?nodeType .
  OPTIONAL { ?node bbo:name ?nodeName . }

  OPTIONAL {
    ?outgoing a bbo:SequenceFlow .
    ?outgoing bbo:has_sourceRef ?node .
  }

  OPTIONAL {
    ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?reachableEnd .
    FILTER(?reachableEnd = ?end)
  }

  FILTER(?nodeType IN (bboExt:ChoreographyTask, bboExt:ExclusiveGateway, bboExt:StartEvent))
}
GROUP BY ?node ?nodeType ?nodeName
HAVING (COUNT(DISTINCT ?outgoing) > 0)
ORDER BY ?nodeName
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?nodeType ?nodeName 
       (COUNT(DISTINCT ?outgoing) AS ?outgoingCount)
       (COUNT(DISTINCT ?reachableEnd) AS ?endsReached)
       (COUNT(DISTINCT ?notReachEnd) AS ?notReachEndCount)
WHERE {
  VALUES ?choreo { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> }
  VALUES ?start { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-A013B90C-3DC6-4212-8569-1E2B58402B21> }
  VALUES ?end { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-E23D1D47-0985-461A-A5F1-774792B4BDCB> }

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?node .
  ?node tai:belongsTo ?choreo .
  ?node a ?nodeType .
  OPTIONAL { ?node bbo:name ?nodeName . }

  OPTIONAL {
    ?outgoing a bbo:SequenceFlow .
    ?outgoing bbo:has_sourceRef ?node .
  }

  OPTIONAL {
    ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?reachableEnd .
    FILTER(?reachableEnd = ?end)
  }

  OPTIONAL {
    ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?notReachEnd .
    ?notReachEnd a bboExt:EndEvent .
    FILTER(?notReachEnd != ?end)
  }

  FILTER(?nodeType IN (bboExt:ChoreographyTask, bboExt:ExclusiveGateway, bboExt:StartEvent))
}
GROUP BY ?node ?nodeType ?nodeName
HAVING (COUNT(DISTINCT ?outgoing) > 0)
