prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?seqFlow ?flowName ?sourceName ?targetName ?gatewayDir WHERE {
  VALUES ?choreo { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> }

  VALUES ?loopNodes {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-69509D2C-03B5-4175-8E2D-C5FE3C7C76FB>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-22214891-5F47-4B8B-ADDC-06E82BD4FCA1>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-B216E792-FFDE-4AEC-AF35-317D250205B0>
  }

  ?seqFlow a bbo:SequenceFlow .
  ?seqFlow tai:belongsTo ?choreo .
  OPTIONAL { ?seqFlow bbo:name ?flowName . }

  ?seqFlow bbo:has_sourceRef ?source .
  ?seqFlow bbo:has_targetRef ?target .

  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }

  OPTIONAL {
    ?loopNodes a bboExt:ExclusiveGateway .
    ?loopNodes bboExt:gatewayDirection ?gatewayDir .
  }

  FILTER(?source = ?loopNodes || ?target = ?loopNodes)
}
ORDER BY ?sourceName ?targetName
LIMIT 50

