SELECT ?node ?nodeName ?canReachEnd WHERE {
  VALUES ?choreo { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> }
  VALUES ?end { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-E23D1D47-0985-461A-A5F1-774792B4BDCB> }

  VALUES ?node {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-BB48F939-F07D-4C27-B96B-02424B7776D3>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-CA197233-FA4B-497C-B86F-5C1B36EA22DF>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-DCF5CEC1-0C21-4BE8-BA02-C70522B864AA>
  }

  OPTIONAL { ?node bbo:name ?nodeName . }

  OPTIONAL {
    ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?endReach .
    FILTER(?endReach = ?end)
    BIND("yes" AS ?canReachEnd)
  }
}
LIMIT 25

